    private int persistCustomers(List<Customer> customers) throws Exception {
        String sql = "MERGE INTO customers (id, name, email, phone, country) KEY(id) VALUES (?, ?, ?, ?, ?)";
        PreparedStatement pstmt = dbConnection.prepareStatement(sql);

        for (Customer customer : customers) {
            pstmt.setString(1, customer.id);
            pstmt.setString(2, customer.name);
            pstmt.setString(3, customer.email);
            pstmt.setString(4, customer.phone);
            pstmt.setString(5, customer.country);
            pstmt.addBatch();
        }

        pstmt.executeBatch();
        return customers.size();
    }

    private int persistOrders(List<Order> orders) throws Exception {
        String orderSql = "MERGE INTO orders (id, customer_id, order_date, total_amount, status) KEY(id) VALUES (?, ?, ?, ?, ?)";
        String itemSql = "INSERT INTO order_items (order_id, product_id, product_name, quantity, price) VALUES (?, ?, ?, ?, ?)";
        
        PreparedStatement orderPstmt = dbConnection.prepareStatement(orderSql);
        PreparedStatement itemPstmt = dbConnection.prepareStatement(itemSql);

        for (Order order : orders) {
            orderPstmt.setString(1, order.id);
            orderPstmt.setString(2, order.customerId);
            orderPstmt.setString(3, order.orderDate);
            orderPstmt.setDouble(4, order.totalAmount);
            orderPstmt.setString(5, order.status);
            orderPstmt.addBatch();

            if (order.items != null) {
                for (OrderItem item : order.items) {
                    itemPstmt.setString(1, item.orderId);
                    itemPstmt.setString(2, item.productId);
                    itemPstmt.setString(3, item.productName);
                    itemPstmt.setInt(4, item.quantity);
                    itemPstmt.setDouble(5, item.price);
                    itemPstmt.addBatch();
                }
            }
        }

        orderPstmt.executeBatch();
        itemPstmt.executeBatch();
        return orders.size();
    }

    private int persistProducts(List<Product> products) throws Exception {
        String sql = "MERGE INTO products (id, name, description, category, price, stock_quantity) KEY(id) VALUES (?, ?, ?, ?, ?, ?)";
        PreparedStatement pstmt = dbConnection.prepareStatement(sql);

        for (Product product : products) {
            pstmt.setString(1, product.id);
            pstmt.setString(2, product.name);
            pstmt.setString(3, product.description);
            pstmt.setString(4, product.category);
            pstmt.setDouble(5, product.price);
            pstmt.setInt(6, product.stockQuantity);
            pstmt.addBatch();
        }

        pstmt.executeBatch();
        return products.size();
    }

    private void logImport(String type, int count, String status, String message) {
        try {
            String sql = "INSERT INTO import_log (import_type, record_count, status, message) VALUES (?, ?, ?, ?)";
            PreparedStatement pstmt = dbConnection.prepareStatement(sql);
            pstmt.setString(1, type);
            pstmt.setInt(2, count);
            pstmt.setString(3, status);
            pstmt.setString(4, message);
            pstmt.executeUpdate();
        } catch (Exception e) {
            e.printStackTrace();
        }
    }

    private String getElementTextContent(Element parent, String tagName) {
        NodeList nodeList = parent.getElementsByTagName(tagName);
        if (nodeList.getLength() > 0) {
            Node node = nodeList.item(0);
            if (node != null) {
                return node.getTextContent();
            }
        }
        return "";
    }

    private double parseDouble(String value) {
        try {
            return Double.parseDouble(value);
        } catch (NumberFormatException e) {
            return 0.0;
        }
    }

    private int parseInt(String value) {
        try {
            return Integer.parseInt(value);
        } catch (NumberFormatException e) {
            return 0;
        }
    }

    private Map<String, Integer> countElements(Element element) {
        Map<String, Integer> counts = new HashMap<>();
        countElementsRecursive(element, counts);
        return counts;
    }

    private void countElementsRecursive(Element element, Map<String, Integer> counts) {
        String tagName = element.getTagName();
        counts.put(tagName, counts.getOrDefault(tagName, 0) + 1);

        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            Node child = children.item(i);
            if (child.getNodeType() == Node.ELEMENT_NODE) {
                countElementsRecursive((Element) child, counts);
            }
        }
    }

    private String buildSuccessResponse(String message, int recordCount) {
        return "<response>" +
               "<status>SUCCESS</status>" +
               "<message>" + escapeXml(message) + "</message>" +
               "<recordCount>" + recordCount + "</recordCount>" +
               "</response>";
    }

    private String buildErrorResponse(String message) {
        return "<response>" +
               "<status>ERROR</status>" +
               "<message>" + escapeXml(message) + "</message>" +
               "<recordCount>0</recordCount>" +
               "</response>";
    }

    private String escapeXml(String text) {
        return text.replace("&", "&amp;")
                   .replace("<", "&lt;")
                   .replace(">", "&gt;")
                   .replace("\"", "&quot;")
                   .replace("'", "&apos;");
    }

